fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let n = n as usize;
    let mut adj = vec![vec![]; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let w = edge[2];
        adj[u].push((v, w));
    }

    let mut distances = vec![vec![i64::MAX; 2]; n];
    distances[0][0] = 0;

    use std::collections::PriorityQueue;
    let mut pq = PriorityQueue::new();
    pq.push(0, 0, 0);

    while let Some((cost, u, switch_used)) = pq.pop() {
        if u == n - 1 {
            return cost;
        }
        if cost > distances[u][switch_used] {
            continue;
        }

        for (v, w) in &adj[u] {
            if switch_used == 0 {
                // Option 1: Don't use the switch
                let new_cost = cost + w;
                if new_cost < distances[*v][0] {
                    distances[*v][0] = new_cost;
                    pq.push(new_cost, *v, 0);
                }

                // Option 2: Use the switch (reverse the edge)
                let new_cost_rev = cost + 2 * w;
                if new_cost_rev < distances[*v][1] {
                    distances[*v][1] = new_cost_rev;
                    pq.push(new_cost_rev, *v, 1);
                }
            } else {
                // Switch has already been used, can't use it again
                let new_cost = cost + w;
                if new_cost < distances[*v][1] {
                    distances[*v][1] = new_cost;
                    pq.push(new_cost, *v, 1);
                }
            }
        }
    }

    if distances[n - 1][0] == i64::MAX && distances[n - 1][1] == i64::MAX {
        -1
    } else {
        std::cmp::min(distances[n - 1][0], distances[n - 1][1])
    }
}

